import 'dart:convert';
import 'package:crypto/crypto.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class SecureStorageService {
  final FlutterSecureStorage _storage = const FlutterSecureStorage(
    aOptions: AndroidOptions(
      encryptedSharedPreferences: true,
      keyCipherAlgorithm: KeyCipherAlgorithm.RSA_ECB_OAEPwithSHA_256andMGF1Padding,
      storageCipherAlgorithm: StorageCipherAlgorithm.AES_GCM_NoPadding,
    ),
    iOptions: IOSOptions(
      accessibility: KeychainAccessibility.first_unlock_this_device,
      accountName: 'payment_module_secure',
    ),
  );

  static const String _tokenPrefix = 'pmt_token_';
  static const String _receiptPrefix = 'pmt_receipt_';
  static const String _configPrefix = 'pmt_config_';

  Future<void> storePaymentToken(String tokenId, String tokenData) async {
    final hmac = _computeHmac(tokenData);
    final envelope = jsonEncode({'data': tokenData, 'hmac': hmac});
    await _storage.write(key: '$_tokenPrefix$tokenId', value: envelope);
  }

  Future<String?> retrievePaymentToken(String tokenId) async {
    final envelope = await _storage.read(key: '$_tokenPrefix$tokenId');
    if (envelope == null) return null;

    final decoded = jsonDecode(envelope) as Map<String, dynamic>;
    final data = decoded['data'] as String;
    final storedHmac = decoded['hmac'] as String;

    if (_computeHmac(data) != storedHmac) {
      await _storage.delete(key: '$_tokenPrefix$tokenId');
      throw SecureStorageTamperException(
        'Payment token integrity check failed for $tokenId',
      );
    }

    return data;
  }

  Future<void> storeReceipt(
    String transactionId,
    String receiptData,
  ) async {
    final hmac = _computeHmac(receiptData);
    final envelope = jsonEncode({
      'data': receiptData,
      'hmac': hmac,
      'stored_at': DateTime.now().toUtc().toIso8601String(),
    });
    await _storage.write(
      key: '$_receiptPrefix$transactionId',
      value: envelope,
    );
  }

  Future<String?> retrieveReceipt(String transactionId) async {
    final envelope = await _storage.read(
      key: '$_receiptPrefix$transactionId',
    );
    if (envelope == null) return null;

    final decoded = jsonDecode(envelope) as Map<String, dynamic>;
    final data = decoded['data'] as String;
    final storedHmac = decoded['hmac'] as String;

    if (_computeHmac(data) != storedHmac) {
      throw SecureStorageTamperException(
        'Receipt integrity check failed for $transactionId',
      );
    }

    return data;
  }

  Future<void> storeConfig(String key, String value) async {
    await _storage.write(key: '$_configPrefix$key', value: value);
  }

  Future<String?> readConfig(String key) async {
    return _storage.read(key: '$_configPrefix$key');
  }

  Future<void> deletePaymentToken(String tokenId) async {
    await _storage.write(key: '$_tokenPrefix$tokenId', value: '');
    await _storage.delete(key: '$_tokenPrefix$tokenId');
  }

  Future<void> clearAllPaymentData() async {
    final all = await _storage.readAll();
    for (final key in all.keys) {
      if (key.startsWith(_tokenPrefix) || key.startsWith(_receiptPrefix)) {
        await _storage.write(key: key, value: '');
        await _storage.delete(key: key);
      }
    }
  }

  String _computeHmac(String data) {
    // In production, use a key derived from device-specific material
    final key = utf8.encode('payment_module_integrity_key_v2');
    final hmacSha256 = Hmac(sha256, key);
    return hmacSha256.convert(utf8.encode(data)).toString();
  }
}

class SecureStorageTamperException implements Exception {
  final String message;
  const SecureStorageTamperException(this.message);

  @override
  String toString() => 'SecureStorageTamperException: $message';
}

