import 'dart:convert';
import 'dart:io';
import 'package:crypto/crypto.dart';
import 'package:http/http.dart' as http;
import '../models/payment_models.dart';
import 'device_integrity_service.dart';

class PaymentGatewayClient {
  final PaymentConfiguration config;
  final DeviceIntegrityService _integrityService;
  final http.Client _httpClient;

  PaymentGatewayClient({
    required this.config,
    required DeviceIntegrityService integrityService,
    http.Client? httpClient,
  }) : _integrityService = integrityService,
       _httpClient = httpClient ?? http.Client();

  Future<Map<String, dynamic>> processPayment(
    PaymentRequest request,
  ) async {
    // Pre-flight integrity check
    final integrity = await _integrityService.getIntegrityLevel();
    if (integrity == DeviceIntegrityLevel.untrusted &&
        config.enforceDeviceIntegrity) {
      return {
        'success': false,
        'error': 'device_integrity_failed',
        'message':
            'Transaction blocked due to device integrity concerns',
      };
    }

    final payload = request.toSecurePayload();
    payload['device_integrity'] = integrity.name;
    payload['merchant_id'] = config.merchantId;

    final response = await _makeSecureRequest(
      '/v1/payments/process',
      payload,
    );

    return response;
  }

  Future<Map<String, dynamic>> verifyReceipt(
    String receiptData,
    String platform,
  ) async {
    final payload = {
      'receipt_data': receiptData,
      'platform': platform,
      'merchant_id': config.merchantId,
      'timestamp': DateTime.now().toUtc().toIso8601String(),
    };

    return _makeSecureRequest('/v1/receipts/verify', payload);
  }

  Future<Map<String, dynamic>> tokenizeCard(
    Map<String, dynamic> cardData,
  ) async {
    // Never send raw card data - this should go through a PCI-compliant
    // tokenization endpoint (e.g., Stripe Elements, Braintree Drop-in)
    final payload = {
      'tokenization_request': cardData,
      'merchant_id': config.merchantId,
    };

    return _makeSecureRequest('/v1/tokens/create', payload);
  }

  Future<Map<String, dynamic>> getTransactionStatus(
    String transactionId,
  ) async {
    final payload = {
      'transaction_id': transactionId,
      'merchant_id': config.merchantId,
    };

    return _makeSecureRequest('/v1/payments/status', payload);
  }

  Future<Map<String, dynamic>> requestRefund(
    String transactionId,
    double amount,
    String reason,
  ) async {
    final integrity = await _integrityService.getIntegrityLevel(
      forceRefresh: true,
    );
    if (integrity == DeviceIntegrityLevel.untrusted) {
      return {
        'success': false,
        'error': 'device_integrity_failed',
        'message': 'Refund blocked due to device integrity concerns',
      };
    }

    final payload = {
      'transaction_id': transactionId,
      'amount': amount,
      'reason': reason,
      'merchant_id': config.merchantId,
      'device_integrity': integrity.name,
    };

    return _makeSecureRequest('/v1/payments/refund', payload);
  }

  Future<Map<String, dynamic>> _makeSecureRequest(
    String endpoint,
    Map<String, dynamic> payload,
  ) async {
    final uri = Uri.parse('${config.gatewayBaseUrl}$endpoint');
    final timestamp = DateTime.now().toUtc().millisecondsSinceEpoch.toString();
    final nonce = _generateNonce();

    final bodyJson = jsonEncode(payload);
    final signature = _computeRequestSignature(
      endpoint,
      bodyJson,
      timestamp,
      nonce,
    );

    try {
      final response = await _httpClient
          .post(
            uri,
            headers: {
              'Content-Type': 'application/json',
              'Authorization': 'Bearer ${config.apiKey}',
              'X-Request-Timestamp': timestamp,
              'X-Request-Nonce': nonce,
              'X-Request-Signature': signature,
              'X-Merchant-Id': config.merchantId,
              'X-SDK-Version': '1.0.0',
              'X-Platform': Platform.isIOS ? 'ios' : 'android',
            },
            body: bodyJson,
          )
          .timeout(config.transactionTimeout);

      if (response.statusCode == 200 || response.statusCode == 201) {
        final responseBody =
            jsonDecode(response.body) as Map<String, dynamic>;

        // Verify response signature if present
        final responseSignature = response.headers['x-response-signature'];
        if (responseSignature != null) {
          final expectedSig = _computeResponseSignature(
            response.body,
            timestamp,
          );
          if (responseSignature != expectedSig) {
            return {
              'success': false,
              'error': 'response_integrity_failed',
              'message': 'Response signature verification failed',
            };
          }
        }

        return responseBody;
      } else {
        return {
          'success': false,
          'error': 'http_error',
          'status_code': response.statusCode,
          'message': 'Gateway returned status ${response.statusCode}',
        };
      }
    } on SocketException catch (e) {
      return {
        'success': false,
        'error': 'network_error',
        'message': 'Network error: ${e.message}',
      };
    } catch (e) {
      return {
        'success': false,
        'error': 'unknown_error',
        'message': e.toString(),
      };
    }
  }

  String _computeRequestSignature(
    String endpoint,
    String body,
    String timestamp,
    String nonce,
  ) {
    final data = '$endpoint|$body|$timestamp|$nonce';
    final key = utf8.encode(config.apiKey);
    final hmacSha256 = Hmac(sha256, key);
    return hmacSha256.convert(utf8.encode(data)).toString();
  }

  String _computeResponseSignature(String body, String timestamp) {
    final data = '$body|$timestamp';
    final key = utf8.encode(config.apiKey);
    final hmacSha256 = Hmac(sha256, key);
    return hmacSha256.convert(utf8.encode(data)).toString();
  }

  String _generateNonce() {
    final random = DateTime.now().microsecondsSinceEpoch;
    return sha256.convert(utf8.encode('$random')).toString().substring(0, 32);
  }

  void dispose() {
    _httpClient.close();
  }
}

// lib/payment_module/core/transaction_manager.dart
import 'dart:async';
import 'dart:convert';
import 'package:crypto/crypto.dart';
import '../models/payment_models.dart';
import 'device_integrity_service.dart';
import 'secure_storage_service.dart';
import 'payment_gateway_client.dart';

class TransactionManager {
  final PaymentGatewayClient _gatewayClient;
  final SecureStorageService _secureStorage;
  final DeviceIntegrityService _integrityService;

  final Map<String, TransactionRecord> _activeTransactions = {};
  final Set<String> _processedIdempotencyKeys = {};
  final StreamController<TransactionEvent> _eventController =
      StreamController<TransactionEvent>.broadcast();

  Stream<TransactionEvent> get transactionEvents => _eventController.stream;

  TransactionManager({
    required PaymentGatewayClient gatewayClient,
    required SecureStorageService secureStorage,
    required DeviceIntegrityService integrityService,
  }) : _gatewayClient = gatewayClient,
       _secureStorage = secureStorage,
       _integrityService = integrityService;

  Future<PaymentResult> executeTransaction(PaymentRequest request) async {
    // Idempotency check
    if (_processedIdempotencyKeys.contains(request.idempotencyKey)) {
      return PaymentResult(
        transactionId: '',
        status: TransactionStatus.failed,
        amount: request.amount,
        currency: request.currency,
        processedAt: DateTime.now().toUtc(),
        errorMessage: 'Duplicate transaction detected',
        errorCode: 'DUPLICATE_IDEMPOTENCY_KEY',
      );
    }

    // Device integrity check (defense-in-depth)
    final integrityLevel = await _integrityService.getIntegrityLevel(
      forceRefresh: true,
    );

    _eventController.add(
      TransactionEvent(
        type: TransactionEventType.integrityChecked,
        data: {'level': integrityLevel.name},
      ),
    );

    if (integrityLevel == DeviceIntegrityLevel.untrusted) {
      _eventController.add(
        TransactionEvent(
          type: TransactionEventType.integrityFailed,
          data: {'level': integrityLevel.name},
        ),
      );

      return PaymentResult(
        transactionId: _generateTransactionId(),
        status: TransactionStatus.integrityCheckFailed,
        amount: request.amount,
        currency: request.currency,
        processedAt: DateTime.now().toUtc(),
        errorMessage:
            'Transaction blocked: device integrity check failed',
        errorCode: 'DEVICE_INTEGRITY_FAILED',
        deviceIntegrityLevel: integrityLevel,
      );
    }

    // Input validation
    final validationError = _validateRequest(request);
    if (validationError != null) {
      return PaymentResult(
        transactionId: '',
        status: TransactionStatus.failed,
        amount: request.amount,
        currency: request.currency,
        processedAt: DateTime.now().toUtc(),
        errorMessage: validationError,
        errorCode: 'VALIDATION_ERROR',
      );
    }

    // Amount bounds check (defense against manipulation)
    if (request.amount <= 0 || request.amount > 999999.99) {
      return PaymentResult(
        transactionId: '',
        status: TransactionStatus.failed,
        amount: request.amount,
        currency: request.currency,
        processedAt: DateTime.now().toUtc(),
        errorMessage: 'Invalid transaction amount',
        errorCode: 'INVALID_AMOUNT',
      );
    }

    _eventController.add(
      TransactionEvent(
        type: TransactionEventType.processing,
        data: {'idempotency_key': request.idempotencyKey},
      ),
    );

    try {
      final response = await _gatewayClient.processPayment(request);

      final transactionId =
          response['transaction_id'] as String? ?? _generateTransactionId();

      PaymentResult result;

      if (response['success'] == true) {
        result = PaymentResult(
          transactionId: transactionId,
          status: TransactionStatus.completed,
          amount: request.amount,
          currency: request.currency,
          processedAt: DateTime.now().toUtc(),
          receiptData: response['receipt'] as String?,
          deviceIntegrityLevel: integrityLevel,
        );

        // Store receipt securely
        if (response['receipt'] != null) {
          await _secureStorage.storeReceipt(
            transactionId,
            response['receipt'] as String,
          );
        }

        _processedIdempotencyKeys.add(request.idempotencyKey);
      } else {
        result = PaymentResult(
          transactionId: transactionId,
          status: _mapErrorToStatus(response['error'] as String?),
          amount: request.amount,
          currency: request.currency,
          processedAt: DateTime.now().toUtc(),
          errorMessage: response['message'] as String?,
          errorCode: response['error'] as String?,
          deviceIntegrityLevel: integrityLevel,
        );
      }

      // Record transaction
      final record = TransactionRecord(
        transactionId: transactionId,
        request: request,
        result: result,
        integrityAtTime: integrityLevel,
        recordedAt: DateTime.now().toUtc(),
      );
      _activeTransactions[transactionId] = record;

      _eventController.add(
        TransactionEvent(
          type:
              result.isSuccessful
                  ? TransactionEventType.completed
                  : TransactionEventType.failed,
          data: result.toJson(),
        ),
      );

      return result;
    } catch (e) {
      final result = PaymentResult(
        transactionId: _generateTransactionId(),
        status: TransactionStatus.failed,
        amount: request.amount,
        currency: request.currency,
        processedAt: DateTime.now().toUtc(),
        errorMessage: 'Transaction processing error: ${e.toString()}',
        errorCode: 'PROCESSING_ERROR',
        deviceIntegrityLevel: integrityLevel,
      );

      _eventController.add(
        TransactionEvent(
          type: TransactionEventType.error,
          data: {'error': e.toString()},
        ),
      );

      return result;
    }
  }

  Future<PaymentResult> refundTransaction(
    String transactionId,
    double amount,
    String reason,
  ) async {
    // Force fresh integrity check for refunds
    final integrityLevel = await _integrityService.getIntegrityLevel(
      forceRefresh: true,
    );

    if (integrityLevel == DeviceIntegrityLevel.untrusted) {
      return PaymentResult(
        transactionId: transactionId,
        status: TransactionStatus.integrityCheckFailed,
        amount: amount,
        currency: 'USD',
        processedAt: DateTime.now().toUtc(),
        errorMessage: 'Refund blocked: device integrity check failed',
        errorCode: 'DEVICE_INTEGRITY_FAILED',
        deviceIntegrityLevel: integrityLevel,
      );
    }

    final response = await _gatewayClient.requestRefund(
      transactionId,
      amount,
      reason,
    );

    if (response['success'] == true) {
      return PaymentResult(
        transactionId: transactionId,
        status: TransactionStatus.refunded,
        amount: amount,
        currency: response['currency'] as String? ?? 'USD',
        processedAt: DateTime.now().toUtc(),
        receiptData: response['refund_receipt'] as String?,
        deviceIntegrityLevel: integrityLevel,
      );
    }

    return PaymentResult(
      transactionId: transactionId,
      status: TransactionStatus.failed,
      amount: amount,
      currency: 'USD',
      processedAt: DateTime.now().toUtc(),
      errorMessage: response['message'] as String?,
      errorCode: response['error'] as String?,
      deviceIntegrityLevel: integrityLevel,
    );
  }

  String? _validateRequest(PaymentRequest request) {
    if (request.amount <= 0) return 'Amount must be positive';
    if (request.currency.length != 3) return 'Invalid currency code';
    if (request.idempotencyKey.isEmpty) return 'Idempotency key required';
    if (request.deviceFingerprint.isEmpty) {
      return 'Device fingerprint required';
    }

    // Verify request integrity hash
    final expectedHash = request.integrityHash;
    if (expectedHash.isEmpty) return 'Request integrity hash missing';

    return null;
  }

  TransactionStatus _mapErrorToStatus(String? error) {
    switch (error) {
      case 'device_integrity_failed':
        return TransactionStatus.integrityCheckFailed;
      case 'requires_verification':
        return TransactionStatus.requiresVerification;
      case 'cancelled':
        return TransactionStatus.cancelled;
      default:
        return TransactionStatus.failed;
    }
  }

  String _generateTransactionId() {
    final timestamp = DateTime.now().toUtc().millisecondsSinceEpoch;
    final hash =
        sha256.convert(utf8.encode('$timestamp')).toString().substring(0, 16);
    return 'txn_$hash';
  }

  TransactionRecord? getTransaction(String transactionId) {
    return _activeTransactions[transactionId];
  }

  void dispose() {
    _eventController.close();
  }
}

enum TransactionEventType {
  integrityChecked,
  integrityFailed,
  processing,
  completed,
  failed,
  error,
  refunded,
}

class TransactionEvent {
  final TransactionEventType type;
  final Map<String, dynamic> data;
  final DateTime timestamp;

  TransactionEvent({required this.type, required this.data})
    : timestamp = DateTime.now().toUtc();
}

// lib/payment_module/iap/iap_service.dart
import 'dart:async';
import 'dart:io';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:in_app_purchase_storekit/in_app_purchase_storekit.dart';
import 'package:in_app_purchase_android/in_app_purchase_android.dart';
import '../models/payment_models.dart';
import '../core/device_integrity_service.dart';
import '../core/secure_storage_service.dart';
import '../core/payment_gateway_client.dart';

class IAPService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final DeviceIntegrityService _integrityService;
  final SecureStorageService _secureStorage;
  final PaymentGatewayClient _gatewayClient;

  StreamSubscription<List<PurchaseDetails>>? _purchaseSubscription;
  final StreamController<IAPEvent> _eventController =
      StreamController<IAPEvent>.broadcast();

  Stream<IAPEvent> get events => _eventController.stream;

  List<ProductDetails> _products = [];
  List<ProductDetails> get products => List.unmodifiable(_products);

  IAPService({
    required DeviceIntegrityService integrityService,
    required SecureStorageService secureStorage,
    required PaymentGatewayClient gatewayClient,
  }) : _integrityService = integrityService,
       _secureStorage = secureStorage,
       _gatewayClient = gatewayClient;

  Future<bool> initialize() async {
    final available = await _iap.isAvailable();
    if (!available) {
      _eventController.add(
        IAPEvent(type: IAPEventType.error, message: 'Store not available'),
      );
      return false;
    }

    _purchaseSubscription = _iap.purchaseStream.listen(
      _handlePurchaseUpdates,
      onError: (error) {
        _eventController.add(
          IAPEvent(
            type: IAPEventType.error,
            message: 'Purchase stream error: $error',
          ),
        );
      },
    );

    return true;
  }

  Future<List<ProductDetails>> loadProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);

    if (response.notFoundIDs.isNotEmpty) {
      _eventController.add(
        IAPEvent(
          type: IAPEventType.productsNotFound,
          message: 'Products not found: ${response.notFoundIDs.join(", ")}',
        ),
      );
    }

    _products = response.productDetails;

    _eventController.add(
      IAPEvent(
        type: IAPEventType.productsLoaded,
        message: 'Loaded ${_products.length} products',
      ),
    );

    return _products;
  }

  Future<bool> purchaseProduct(ProductDetails product) async {
    // Pre-purchase integrity check
    final integrity = await _integrityService.getIntegrityLevel(
      forceRefresh: true,
    );

    if (integrity == DeviceIntegrityLevel.untrusted) {
      _eventController.add(
        IAPEvent(
          type: IAPEventType.integrityFailed,
          message: 'Purchase blocked: device integrity check failed',
        ),
      );
      return false;
    }

    final purchaseParam = PurchaseParam(productDetails: product);

    try {
      // Determine if consumable or non-consumable
      final success = await _iap.buyNonConsumable(
        purchaseParam: purchaseParam,
      );

      if (!success) {
        _eventController.add(
          IAPEvent(
            type: IAPEventType.error,
            message: 'Purchase initiation failed',
          ),
        );
      }

      return success;
    } catch (e) {
      _eventController.add(
        IAPEvent(
          type: IAPEventType.error,
          message: 'Purchase error: ${e.toString()}',
        ),
      );
      return false;
    }
  }

  Future<bool> purchaseConsumable(ProductDetails product) async {
    final integrity = await _integrityService.getIntegrityLevel(
      forceRefresh: true,
    );

    if (integrity == DeviceIntegrityLevel.untrusted) {
      _eventController.add(
        IAPEvent(
          type: IAPEventType.integrityFailed,
          message: 'Purchase blocked: device integrity check failed',
        ),
      );
      return false;
    }

    final purchaseParam = PurchaseParam(productDetails: product);

    try {
      return await _iap.buyConsumable(purchaseParam: purchaseParam);
    } catch (e) {
      _eventController.add(
        IAPEvent(
          type: IAPEventType.error,
          message: 'Consumable purchase error: ${e.toString()}',
        ),
      );
      return false;
    }
  }

  Future<void> restorePurchases() async {
    await _iap.restorePurchases();
  }

  Future<void> _handlePurchaseUpdates(
    List<PurchaseDetails> purchases,
  ) async {
    for (final purchase in purchases) {
      switch (purchase.status) {
        case PurchaseStatus.pending:
          _eventController.add(
            IAPEvent(
              type: IAPEventType.purchasePending,
              message: 'Purchase pending: ${purchase.productID}',
              purchaseDetails: purchase,
            ),
          );
          break;

        case PurchaseStatus.purchased:
        case PurchaseStatus.restored:
          final verified = await _verifyPurchaseServerSide(purchase);
          if (verified) {
            _eventController.add(
              IAPEvent(
                type: IAPEventType.purchaseCompleted,
                message: 'Purchase verified: ${purchase.productID}',
                purchaseDetails: purchase,
              ),
            );

            // Store receipt
            final receiptData =
                purchase.verificationData.serverVerificationData;
            await _secureStorage.storeReceipt(
              purchase.purchaseID ?? purchase.productID,
              receiptData,
            );
          } else {
            _eventController.add(
              IAPEvent(
                type: IAPEventType.verificationFailed,
                message:
                    'Server verification failed: ${purchase.productID}',
                purchaseDetails: purchase,
              ),
            );
          }

          if (purchase.pendingCompletePurchase) {
            await _iap.completePurchase(purchase);
          }
          break;

        case PurchaseStatus.error:
          _eventController.add(
            IAPEvent(
              type: IAPEventType.error,
              message:
                  'Purchase error: ${purchase.error?.message ?? "Unknown"}',
              purchaseDetails: purchase,
            ),
          );

          if (purchase.pendingCompletePurchase) {
            await _iap.completePurchase(purchase);
          }
          break;

        case PurchaseStatus.canceled:
          _eventController.add(
            IAPEvent(
              type: IAPEventType.purchaseCancelled,
              message: 'Purchase cancelled: ${purchase.productID}',
              purchaseDetails: purchase,
            ),
          );
          break;
      }
    }
  }

  Future<bool> _verifyPurchaseServerSide(PurchaseDetails purchase) async {
    try {
      final receiptData =
          purchase.verificationData.serverVerificationData;
      final platform = Platform.isIOS ? 'ios' : 'android';

      final response = await _gatewayClient.verifyReceipt(
        receiptData,
        platform,
      );

      return response['valid'] == true;
    } catch (e) {
      _eventController.add(
        IAPEvent(
          type: IAPEventType.error,
          message: 'Receipt verification error: ${e.toString()}',
        ),
      );
      return false;
    }
  }

  void dispose() {
    _purchaseSubscription?.cancel();
    _eventController.close();
  }
}

enum IAPEventType {
  productsLoaded,
  productsNotFound,
  purchasePending,
  purchaseCompleted,
  purchaseCancelled,
  verificationFailed,
  integrityFailed,
  error,
}

class IAPEvent {
  final IAPEventType type;
  final String message;
  final PurchaseDetails? purchaseDetails;
  final DateTime timestamp;

  IAPEvent({
    required this.type,
    required this.message,
    this.purchaseDetails,
  }) : timestamp = DateTime.now().toUtc();
}

// lib/payment_module/wallet/mobile_wallet_service.dart
import 'dart:io';
import 'package:pay/pay.dart';
import '../models/payment_models.dart';
import '../core/device_integrity_service.dart';
import '../core/transaction_manager.dart';

class MobileWalletService {
  final DeviceIntegrityService _integrityService;
  final TransactionManager _transactionManager;
  final PaymentConfiguration _config;

  Pay? _payClient;

  MobileWalletService({
    required DeviceIntegrityService integrityService,
    required TransactionManager transactionManager,
    required PaymentConfiguration config,
  }) : _integrityService = integrityService,
       _transactionManager = transactionManager,
       _config = config;

  Future<void> initialize() async {
    final paymentConfigurations = <PayProvider, PaymentConfiguration>{};

    if (Platform.isIOS) {
      _payClient = Pay({
        PayProvider.apple_pay: PaymentConfiguration.fromJsonString(
          _buildApplePayConfig(),
        ),
      });
    } else if (Platform.isAndroid) {
      _payClient = Pay({
        PayProvider.google_pay: PaymentConfiguration.fromJsonString(
          _buildGooglePayConfig(),
        ),
      });
    }
  }

  Future<bool> isWalletAvailable() async {
    if (_payClient == null) return false;

    try {
      final provider =
          Platform.isIOS ? PayProvider.apple_pay : PayProvider.google_pay;
      final result = await _payClient!.userCanPay(provider);
      return result;
    } catch (e) {
      return false;
    }
  }

  Future<PaymentResult> processWalletPayment({
    required double amount,
    required String currency,
    required String description,
    required String idempotencyKey,
    List<PaymentItem>? items,
  }) async {
    // Integrity check before wallet payment
    final integrity = await _integrityService.getIntegrityLevel(
      forceRefresh: true,
    );

    if (integrity == DeviceIntegrityLevel.untrusted) {
      return PaymentResult(
        transactionId: '',
        status: TransactionStatus.integrityCheckFailed,
        amount: amount,
        currency: currency,
        processedAt: DateTime.now().toUtc(),
        errorMessage: 'Wallet payment blocked: device integrity failed',
        errorCode: 'DEVICE_INTEGRITY_FAILED',
        deviceIntegrityLevel: integrity,
      );
    }

    final paymentItems =
        items ??
        [
          PaymentItem(
            label: description,
            amount: amount.toStringAsFixed(2),
            status: PaymentItemStatus.final_price,
          ),
        ];

    try {
      final provider =
          Platform.isIOS ? PayProvider.apple_pay : PayProvider.google_pay;

      final result = await _payClient!.showPaymentSelector(
        provider,
        paymentItems,
      );

      // Process through our transaction manager
      final fingerprint = await _integrityService.generateDeviceFingerprint();

      final request = PaymentRequest(
        idempotencyKey: idempotencyKey,
        amount: amount,
        currency: currency,
        method:
            Platform.isIOS ? PaymentMethod.applePay : PaymentMethod.googlePay,
        description: description,
        metadata: {'wallet_token': result.toString()},
        deviceFingerprint: fingerprint,
      );

      return _transactionManager.executeTransaction(request);
    } catch (e) {
      return PaymentResult(
        transactionId: '',
        status: TransactionStatus.failed,
        amount: amount,
        currency: currency,
        processedAt: DateTime.now().toUtc(),
        errorMessage: 'Wallet payment error: ${e.toString()}',
        errorCode: 'WALLET_ERROR',
        deviceIntegrityLevel: integrity,
      );
    }
  }

  String _buildApplePayConfig() {
    return '''
    {
      "provider": "apple_pay",
      "data": {
        "merchantIdentifier": "${_config.merchantId}",
        "displayName": "Payment",
        "merchantCapabilities": ["3DS", "debit", "credit"],
        "supportedNetworks": ["amex", "visa", "discover", "masterCard"],
        "countryCode": "US",
        "currencyCode": "USD",
        "requiredBillingContactFields": ["emailAddress", "name", "postalAddress"],
        "requiredShippingContactFields": []
      }
    }
    ''';
  }

  String _buildGooglePayConfig() {
    return '''
    {
      "provider": "google_pay",
      "data": {
        "environment": "${_config.sandboxMode ? "TEST" : "PRODUCTION"}",
        "apiVersion": 2,
        "apiVersionMinor": 0,
        "allowedPaymentMethods": [
          {
            "type": "CARD",
            "parameters": {
              "allowedAuthMethods": ["PAN_ONLY", "CRYPTOGRAM_3DS"],
              "allowedCardNetworks": ["AMEX", "DISCOVER", "MASTERCARD", "VISA"]
            },
            "tokenizationSpecification": {
              "type": "PAYMENT_GATEWAY",
              "parameters": {
                "gateway": "stripe",
                "gatewayMerchantId": "${_config.merchantId}"
              }
            }
          }
        ],
        "merchantInfo": {
          "merchantId": "${_config.merchantId}",
          "merchantName": "Payment"
        },
        "transactionInfo": {
          "totalPriceStatus": "FINAL",
          "countryCode": "US",
          "currencyCode": "USD"
        }
      }
    }
    ''';
  }
}

// lib/payment_module/core/payment_engine.dart
import 'dart:async';
import '../models/payment_models.dart';
import 'device_integrity_service.dart';
import 'secure_storage_service.dart';
import 'payment_gateway_client.dart';
import 'transaction_manager.dart';
import '../iap/iap_service.dart';
import '../wallet/mobile_wallet_service.dart';

class PaymentEngine {
  final PaymentConfiguration config;

  late final DeviceIntegrityService integrityService;
  late final SecureStorageService secureStorage;
  late final PaymentGatewayClient gatewayClient;
  late final TransactionManager transactionManager;
  late final IAPService iapService;
  late final MobileWalletService walletService;

  bool _initialized = false;
  DeviceIntegrityResult? _initialIntegrityResult;

  PaymentEngine({required this.config});

  Future<PaymentEngineInitResult> initialize() async {
    if (_initialized) {
      return PaymentEngineInitResult(
        success: true,
        integrityResult: _initialIntegrityResult!,
      );
    }

    // Initialize core services
    integrityService = DeviceIntegrityService();
    secureStorage = SecureStorageService();

    // Perform initial integrity check
    _initialIntegrityResult =
        await integrityService.performFullIntegrityCheck();

    if (_initialIntegrityResult!.level == DeviceIntegrityLevel.untrusted &&
        config.enforceDeviceIntegrity) {
      return PaymentEngineInitResult(
        success: false,
        integrityResult: _initialIntegrityResult!,
        errorMessage:
            'Payment engine initialization blocked: device integrity check failed. '
            'Checks: ${_initialIntegrityResult!.checks}',
      );
    }

    gatewayClient = PaymentGatewayClient(
      config: config,
      integrityService: integrityService,
    );

    transactionManager = TransactionManager(
      gatewayClient: gatewayClient,
      secureStorage: secureStorage,
      integrityService: integrityService,
    );

    iapService = IAPService(
      integrityService: integrityService,
      secureStorage: secureStorage,
      gatewayClient: gatewayClient,
    );

    walletService = MobileWalletService(
      integrityService: integrityService,
      transactionManager: transactionManager,
      config: config,
    );

    // Initialize IAP
    await iapService.initialize();

    // Initialize wallet
    await walletService.initialize();

    _initialized = true;

    return PaymentEngineInitResult(
      success: true,
      integrityResult: _initialIntegrityResult!,
    );
  }

  Future<PaymentResult> processPayment(PaymentRequest request) async {
    _ensureInitialized();
    return transactionManager.executeTransaction(request);
  }

  Future<PaymentResult> processWalletPayment({
    required double amount,
    required String currency,
    required String description,
    required String idempotencyKey,
  }) async {
    _ensureInitialized();
    return walletService.processWalletPayment(
      amount: amount,
      currency: currency,
      description: description,
      idempotencyKey: idempotencyKey,
    );
  }

  Future<PaymentResult> refund(
    String transactionId,
    double amount,
    String reason,
  ) async {
    _ensureInitialized();
    return transactionManager.refundTransaction(
      transactionId,
      amount,
      reason,
    );
  }

  Future<DeviceIntegrityResult> checkDeviceIntegrity() async {
    return integrityService.performFullIntegrityCheck();
  }

  Future<String> getDeviceFingerprint() async {
    return integrityService.generateDeviceFingerprint();
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw StateError(
        'PaymentEngine not initialized. Call initialize() first.',
      );
    }
  }

  void dispose() {
    transactionManager.dispose();
    iapService.dispose();
    gatewayClient.dispose();
  }
}

class PaymentEngineInitResult {
  final bool success;
  final DeviceIntegrityResult integrityResult;
  final String? errorMessage;

  const PaymentEngineInitResult({
    required this.success,
    required this.integrityResult,
    this.errorMessage,
  });
}

// lib/payment_module/utils/pci_compliance_utils.dart
import 'dart:convert';
import 'package:crypto/crypto.dart';

class PCIComplianceUtils {
  /// Masks a card number showing only last 4 digits
  static String maskCardNumber(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\D'), '');
    if (cleaned.length < 4) return '****';
    final lastFour = cleaned.substring(cleaned.length - 4);
    return '**** **** **** $lastFour';
  }

  /// Validates card number using Luhn algorithm (for UI validation only)
  static bool validateCardNumberLuhn(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\D'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;

    int sum = 0;
    bool alternate = false;

    for (int i = cleaned.length - 1; i >= 0; i--) {
      int digit = int.parse(cleaned[i]);

      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }

      sum += digit;
      alternate = !alternate;
    }

    return sum % 10 == 0;
  }

  /// Detects card brand from number prefix
  static String detectCardBrand(String cardNumber) {
    final cleaned = cardNumber.replaceAll(RegExp(r'\D'), '');

    if (cleaned.startsWith('4')) return 'visa';
    if (cleaned.startsWith('5') &&
        int.parse(cleaned[1]) >= 1 &&
        int.parse(cleaned[1]) <= 5) {
      return 'mastercard';
    }
    if (cleaned.startsWith('34') || cleaned.startsWith('37')) return 'amex';
    if (cleaned.startsWith('6011') || cleaned.startsWith('65')) {
      return 'discover';
    }

    return 'unknown';
  }

  /// Sanitizes input to prevent injection in payment fields
  static String sanitizeInput(String input) {
    return input
        .replaceAll(RegExp(r'[<>"\x27;(){}]'), '')
        .replaceAll(RegExp(r'[\x00-\x1F\x7F]'), '')
        .trim();
  }

  /// Generates a secure idempotency key
